// Parse FluentSupport webhook payload
// FluentSupport sends ticket data on agent response or ticket close events
const body = items[0].json.body || items[0].json;
const ticket = body.ticket || body;

// Extract ticket ID
const ticketId = ticket.id || ticket.ticket_id || body.ticket_id;
if (!ticketId) {
  throw new Error('No ticket_id found in webhook payload');
}

// Get response count from ticket data
const responseCount = parseInt(ticket.response_count || ticket.responses_count || 0);

// Detect event type from webhook payload
// FluentSupport may send: status changes, new responses, etc.
let eventType = 'agent_response';
const status = (ticket.status || '').toLowerCase();
const eventField = body.event || body.action || body.type || '';

if (status === 'closed' || eventField.includes('closed') || eventField.includes('close')) {
  eventType = 'ticket_closed';
}

return {
  json: {
    ticket_id: parseInt(ticketId),
    response_count: responseCount,
    event_type: eventType
  }
};
